class Solution:
    def maxBalancedSubsequenceSum(self, nums):
        n = len(nums)
        b = [nums[i] - i for i in range(n)]
        dp = [0] * n
        ans = float('-inf')
        for i in range(n):
            best = 0
            for j in range(i):
                if b[j] <= b[i] and dp[j] > best:
                    best = dp[j]
            dp[i] = nums[i] + best
            if dp[i] > ans:
                ans = dp[i]
        return ans

