class Solution:
    def maxBalancedSubsequenceSum(self, nums):
        n = len(nums)
        b = [nums[i] - i for i in range(n)]
        sorted_b = sorted(set(b))
        rank = {v: i + 1 for i, v in enumerate(sorted_b)}
        size = len(sorted_b)
        NEG = float('-inf')
        tree = [NEG] * (size + 1)

        def update(pos, val):
            while pos <= size:
                if tree[pos] < val:
                    tree[pos] = val
                pos += pos & (-pos)

        def query(pos):
            res = NEG
            while pos > 0:
                if tree[pos] > res:
                    res = tree[pos]
                pos -= pos & (-pos)
            return res

        ans = NEG
        for i in range(n):
            r = rank[b[i]]
            best_prev = query(r)
            dp_i = nums[i] + max(0, best_prev)
            if dp_i > ans:
                ans = dp_i
            update(r, dp_i)
        return ans

