var maxBalancedSubsequenceSum = function(nums) {
    const n = nums.length;
    const b = new Array(n);
    for (let i = 0; i < n; i++) b[i] = nums[i] - i;
    const sortedB = Array.from(new Set(b)).sort((a, c) => a - c);
    const rank = new Map();
    sortedB.forEach((v, i) => rank.set(v, i + 1));
    const size = sortedB.length;
    const NEG = -Infinity;
    const tree = new Array(size + 1).fill(NEG);

    function update(pos, val) {
        while (pos <= size) {
            if (tree[pos] < val) tree[pos] = val;
            pos += pos & (-pos);
        }
    }
    function query(pos) {
        let res = NEG;
        while (pos > 0) {
            if (tree[pos] > res) res = tree[pos];
            pos -= pos & (-pos);
        }
        return res;
    }

    let ans = NEG;
    for (let i = 0; i < n; i++) {
        const r = rank.get(b[i]);
        const bestPrev = query(r);
        const dpI = nums[i] + Math.max(0, bestPrev);
        if (dpI > ans) ans = dpI;
        update(r, dpI);
    }
    return ans;
};
